#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[100001];
        scanf("%s", A);
        int balance = 0, max_balance = 0;
        for (int i = 0; i < strlen(A); i++) {
            if (A[i] == '(') balance++;
            else balance--;
            max_balance = (max_balance > balance) ? max_balance : balance;
        }
        for (int i = 0; i < max_balance; i++) printf("(");
        for (int i = 0; i < max_balance; i++) printf(")");
        printf("\n");
    }
    return 0;
}

